"use client"

import { useState, useEffect } from "react"
import Image from "next/image"
import Link from "next/link"
import defaultBannerImage from "@/scr/IMG_8366.webp"
import { useAdmin } from "@/lib/admin-context"
import { AdminLoginDialog } from "@/components/admin-login-dialog"
import { Button } from "@/components/ui/button"

const DEFAULT_BANNER_IMAGE = defaultBannerImage.src

export function Banner() {
  const { isAdmin } = useAdmin()
  const [mounted, setMounted] = useState(false)

  useEffect(() => {
    setMounted(true)
  }, [])

  return (
    <div className="relative w-full h-[27rem] md:h-[36rem] bg-background overflow-hidden">
      <Image
        src={DEFAULT_BANNER_IMAGE}
        alt="배너 이미지"
        fill
        className="object-cover"
        style={{
          objectPosition: "50% 0%",
          transform: "scale(1)",
          transformOrigin: "center center",
        }}
        priority
      />
      <div className="absolute inset-0 bg-gradient-to-t from-background via-background/60 to-transparent pointer-events-none" />
      <div className="absolute inset-0 flex items-center justify-center">
        <div className="text-center">
          <Link href="/" className="group flex items-center justify-center">
            <h1 
              className="text-4xl md:text-6xl font-bold text-white hover:text-white/90 transition-colors drop-shadow-[2px_2px_0px_rgba(0,0,0,0.1)]"
              style={{ fontFamily: "'PyeongChangPeace-Bold', sans-serif", WebkitTextStroke: "1px black" }}
            >
              고래상어
            </h1>
          </Link>
        </div>
      </div>
      
      {/* Admin login button if not logged in */}
      {mounted && !isAdmin && (
        <div className="absolute top-3 right-3">
          <AdminLoginDialog>
            <Button variant="ghost" size="sm" className="bg-background/60 hover:bg-background/80 text-xs">
              관리자
            </Button>
          </AdminLoginDialog>
        </div>
      )}
      
      {mounted && isAdmin && (
        <div className="absolute top-3 right-3 flex gap-2">
          <Button variant="ghost" size="sm" className="bg-background/60 hover:bg-background/80 text-xs" onClick={() => window.location.reload()}>
            새로고침
          </Button>
        </div>
      )}

      <div className="absolute bottom-0 left-0 right-0 h-px bg-border" />
    </div>
  )
}

