"use client"

import Link from "next/link"
import { usePathname } from "next/navigation"
import { cn } from "@/lib/utils"
import { useAdmin } from "@/lib/admin-context"
import { Button } from "@/components/ui/button"
import { User, Briefcase, BookOpen, Image, LogOut } from "lucide-react"

const navItems = [
  { href: "/profile", label: "작가 프로필", icon: User },
  { href: "/portfolio", label: "포트폴리오", icon: Briefcase },
  { href: "/webtoon", label: "웹툰", icon: BookOpen },
  { href: "/illustration", label: "일러스트", icon: Image },
]

export function Navigation() {
  const pathname = usePathname()
  const { isAdmin, logout } = useAdmin()

  return (
    <nav className="sticky top-0 z-50 w-full bg-background/95 backdrop-blur supports-[backdrop-filter]:bg-background/60 border-b border-border">
      <div className="container mx-auto px-4">
        <div className="flex items-center justify-between h-14">
          <ul className="flex items-center gap-1 md:gap-2">
            {navItems.map((item) => {
              const Icon = item.icon
              const isActive = pathname === item.href
              return (
                <li key={item.href}>
                  <Link
                    href={item.href}
                    className={cn(
                      "flex items-center gap-2 px-3 py-2 rounded-md text-sm transition-colors font-[family-name:var(--font-pixel)]",
                      isActive
                        ? "bg-primary text-primary-foreground"
                        : "text-muted-foreground hover:text-foreground hover:bg-secondary"
                    )}
                  >
                    <Icon className="w-4 h-4" />
                    <span className="hidden sm:inline">{item.label}</span>
                  </Link>
                </li>
              )
            })}
          </ul>
          {isAdmin && (
            <Button
              variant="ghost"
              size="sm"
              onClick={logout}
              className="text-muted-foreground hover:text-foreground"
            >
              <LogOut className="w-4 h-4 mr-2" />
              <span className="hidden sm:inline">로그아웃</span>
            </Button>
          )}
        </div>
      </div>
    </nav>
  )
}
