"use client";

import { useEffect, useState } from "react";

export function StarDecorations() {
  const [mounted, setMounted] = useState(false);

  useEffect(() => {
    setMounted(true);
  }, []);

  if (!mounted) return null;

  return (
    <div className="pointer-events-none fixed inset-0 overflow-hidden z-50">
      {/* Bottom Left Star */}
      <div className="absolute bottom-10 left-10 md:bottom-20 md:left-20 opacity-80 animate-pulse drop-shadow-md">
        <svg width="64" height="64" viewBox="0 0 100 100" fill="none" xmlns="http://www.w3.org/2000/svg">
          <path d="M50 0L53.5 35.5L89 50L53.5 64.5L50 100L46.5 64.5L11 50L46.5 35.5L50 0Z" fill="white" stroke="#dcd0d5" strokeWidth="2" />
          <path d="M75 25L77.5 40L92.5 42.5L77.5 45L75 60L72.5 45L57.5 42.5L72.5 40L75 25Z" fill="white" stroke="#dcd0d5" strokeWidth="1.5" />
          <path d="M25 75L26.5 82.5L34 85L26.5 87.5L25 95L23.5 87.5L16 85L23.5 82.5L25 75Z" fill="white" stroke="#dcd0d5" strokeWidth="1" />
        </svg>
      </div>

      {/* Bottom Right Star */}
      <div className="absolute bottom-16 right-8 md:bottom-24 md:right-16 opacity-80 animate-pulse drop-shadow-md" style={{ animationDelay: '1s' }}>
        <svg width="80" height="80" viewBox="0 0 100 100" fill="none" xmlns="http://www.w3.org/2000/svg">
          <path d="M50 0L53.5 35.5L89 50L53.5 64.5L50 100L46.5 64.5L11 50L46.5 35.5L50 0Z" fill="white" stroke="#dcd0d5" strokeWidth="2" />
          <path d="M25 25L27.5 40L42.5 42.5L27.5 45L25 60L22.5 45L7.5 42.5L22.5 40L25 25Z" fill="white" stroke="#dcd0d5" strokeWidth="1.5" />
          <circle cx="80" cy="20" r="2" fill="white" />
          <circle cx="20" cy="80" r="1.5" fill="white" />
        </svg>
      </div>
    </div>
  );
}
